149.         /// Marks the scope as failed with low-cardinality error.type attribute.
150.         /// </summary>
151.         /// <param name="errorCode">Error code to associate with the failed scope.</param>
152.         public void Failed(string errorCode)
153.         {
154.             _activityAdapter?.MarkFailed((Exception?)null, errorCode);
155.         }
